let dotNetRef = null;
let timeoutMs = 300000;
let timerId = null;
let isIdle = false;

const events = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('NotifyActive');
    }
    resetTimer();
}

function resetTimer() {
    if (timerId !== null) {
        clearTimeout(timerId);
    }
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('NotifyIdle');
    }, timeoutMs);
}

export function initialize(ref, timeout) {
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(e => document.addEventListener(e, onActivity, { passive: true }));
    resetTimer();
}

export function dispose() {
    if (timerId !== null) {
        clearTimeout(timerId);
        timerId = null;
    }
    events.forEach(e => document.removeEventListener(e, onActivity));
    dotNetRef = null;
    isIdle = false;
}

